"use strict";(self.webpackChunksentinel_docs=self.webpackChunksentinel_docs||[]).push([[2576],{13050:e=>{e.exports=JSON.parse('{"version":{"pluginId":"sdk","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/sdk/","label":"\ud83d\udcd8 Overview","docId":"README","unlisted":false},{"type":"link","href":"/sdk/golang","label":"\ud83d\udd27 Golang","docId":"golang","unlisted":false},{"type":"link","href":"/sdk/javascript","label":"\ud83d\udce6 Javascript","docId":"javascript","unlisted":false},{"type":"link","href":"/sdk/python","label":"\ud83d\udc0d Python","docId":"python","unlisted":false},{"type":"link","href":"/sdk/ai-connect","label":"\ud83e\udd16 AI Connect","docId":"ai-connect","unlisted":false},{"type":"link","href":"/sdk/x402","label":"\ud83d\udcb3 x402","docId":"x402","unlisted":false},{"type":"link","href":"/sdk/plan-manager","label":"\ud83d\udccb Plan Manager","docId":"plan-manager","unlisted":false}]},"docs":{"ai-connect":{"id":"ai-connect","title":"AI Connect","description":"Sentinel AI Connect is a community-maintained JavaScript library for integrating Sentinel dVPN connectivity into AI agents and automation workflows.","sidebar":"tutorialSidebar"},"golang":{"id":"golang","title":"Golang","description":"The Go SDK is the most complete of the three - it covers the full stack from blockchain client operations down to native VPN tunnel management. Built on Cosmos SDK and CometBFT, it provides everything needed to query chain state, sign transactions, communicate with nodes, and run WireGuard, V2Ray, or OpenVPN tunnels. This is the SDK used by node operators and service builders.","sidebar":"tutorialSidebar"},"javascript":{"id":"javascript","title":"Javascript","description":"The JavaScript SDK lets you interact with the Sentinel blockchain from any browser or Node.js environment. It extends CosmJS, the standard JavaScript library for Cosmos chains - adding Sentinel-specific queries, transactions, and VPN session management on top. If you\'ve worked with CosmJS before, you\'ll feel right at home.","sidebar":"tutorialSidebar"},"plan-manager":{"id":"plan-manager","title":"Plan Manager","description":"Sentinel Plan Manager is the community-built commerce layer for Sentinel dVPN. It lets you create on-chain subscription plans, curate node pools, manage subscribers, and issue fee grants. Built on top of the community blue-js-sdk.","sidebar":"tutorialSidebar"},"python":{"id":"python","title":"Python","description":"The Python SDK provides a straightforward way to query the Sentinel blockchain, manage subscriptions, and handle VPN sessions from Python. It talks to the chain over gRPC using sentinel-protobuf for message definitions and mospy for transaction signing. It\'s a good fit for scripting, automation, and building backend services that need to interact with Sentinel nodes.","sidebar":"tutorialSidebar"},"README":{"id":"README","title":"Overview","description":"Sentinel ships official SDKs for Go, JavaScript, and Python - each covering a different language and use case, but all letting you query chain state, manage subscriptions and sessions, and connect to dVPN nodes. The community has also built additional SDKs and libraries that extend support to other languages and use cases; those are listed under Community SDKs below and are not officially maintained by the Sentinel team.","sidebar":"tutorialSidebar"},"x402":{"id":"x402","title":"x402","description":"x402 is a community-built payments layer that lets AI agents pay USDC on Base or Solana for private VPN access through the Sentinel dVPN network of 900+ decentralized nodes.","sidebar":"tutorialSidebar"}}}}')}}]);